// ─── HAVERSINE-AFSTAND ────────────────────────────────────────────────────────
function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371; // aardstraal in km
  const toRad = (g) => g * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat / 2) ** 2 +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) ** 2;
  return 2 * R * Math.asin(Math.sqrt(a));
}

/**
 * Afstand in km tussen twee PC4-postcodes (eerste 4 cijfers).
 * Accepteert '5735', '5735AB', '5735 AB' — alles na de cijfers wordt genegeerd.
 * @returns {number|null} afstand in km, of null als een postcode onbekend is
 */
export function pc4Distance(a, b) {
  const pa = normalizePc4(a), pb = normalizePc4(b);
  if (!pa || !pb) return null;
  const ca = PC4[pa], cb = PC4[pb];
  if (!ca || !cb) return null;
  if (pa === pb) return 0;
  return haversineKm(ca[0], ca[1], cb[0], cb[1]);
}

/** Geeft true als de PC4 bestaat in de dataset (bruikbaar voor postcodevalidatie). */
export function pc4Exists(p) {
  const n = normalizePc4(p);
  return !!(n && PC4[n]);
}

function normalizePc4(p) {
  if (!p) return null;
  const m = String(p).trim().match(/^(\d{4})/);
  return m ? m[1] : null;
}
